'use client';

import * as React from 'react';

// вопрос POC №9: банковская библиотека на React 19 внутри 'use client'
// (SSR через ssr-слой + гидратация + интерактивность)
import { Button } from '@alfalab/core-components-button';

import { echoOnServer } from '../actions';

import '@alfalab/core-components-button/desktop/default.desktop.css';
import './counter.css';

export function Counter({ initial }: { initial: number }) {
    const [count, setCount] = React.useState(initial);
    const [serverEcho, setServerEcho] = React.useState<string | null>(null);

    return (
        <div style={{ border: '1px solid #ccc', padding: 12, marginTop: 12 }}>
            <Button
                dataTestId='inc'
                view='primary'
                size={32}
                onClick={() => setCount((c) => c + 1)}
            >
                +1 (core-components)
            </Button>{' '}
            <span data-testid='count'>{count}</span>{' '}
            <button
                data-testid='call-action'
                type='button'
                onClick={async () => {
                    const result = await echoOnServer(count);

                    setServerEcho(result);
                }}
            >
                вызвать server action
            </button>
            {serverEcho ? <p data-testid='echo'>{serverEcho}</p> : null}
        </div>
    );
}
